package com.panini.back.service; import com.panini.back.dto.CollectionDtos.UpsertItemRequest; import com.panini.back.dto.DashboardResponse; import com.panini.back.entity.CollectionItem; import com.panini.back.entity.Sticker; import com.panini.back.entity.User; import com.panini.back.repository.CollectionItemRepository; import com.panini.back.repository.StickerRepository; import com.panini.back.repository.UserRepository; import org.springframework.stereotype.Service; import java.util.*; @Service public class CollectionService { private final CollectionItemRepository items; private final StickerRepository stickers; private final UserRepository users; public CollectionService(CollectionItemRepository items, StickerRepository stickers, UserRepository users){ this.items=items; this.stickers=stickers; this.users=users; } public List<CollectionItem> myItems(String username){ return items.findByUser_Username(username); } public CollectionItem upsert(String username, UpsertItemRequest req){ User user=users.findByUsername(username).orElseThrow(()->new IllegalArgumentException("User not found")); Sticker sticker=stickers.findByCode(req.stickerCode).orElseThrow(()->new IllegalArgumentException("Sticker not found")); CollectionItem item=items.findByUser_UsernameAndSticker_Code(username, req.stickerCode).orElseGet(CollectionItem::new); item.setUser(user); item.setSticker(sticker); item.setQuantityOwned(req.quantityOwned==null?0:req.quantityOwned); item.setFavorite(req.favorite!=null && req.favorite); return items.save(item); } public DashboardResponse dashboard(String username){ List<CollectionItem> list=items.findByUser_Username(username); long total=stickers.count(); long owned=list.stream().filter(i->i.getQuantityOwned()!=null && i.getQuantityOwned()>0).count(); long duplicates=list.stream().filter(i->i.getQuantityOwned()!=null && i.getQuantityOwned()>1).count(); long missing=Math.max(0,total-owned); double completion= total==0?0:Math.round((owned*10000.0/total))/100.0; String display=users.findByUsername(username).map(User::getDisplayName).orElse(username); return new DashboardResponse(username, display, total, owned, duplicates, missing, completion); } }
